// Java 25 exam prep - Deque and ArrayDeque
// Learn: use ArrayDeque as a stack and a double-ended queue.
Deque<Integer> stack = new ArrayDeque<>();
// push adds to the front like a stack.
stack.push(1);
stack.push(2);
int top = stack.pop();
stack.offerLast(9);
System.out.println(top + " " + stack.peekFirst() + " " + stack.peekLast());
